import React from "react";
import { useNavigate } from "react-router-dom";
import { FaUserCircle, FaRegBell, FaHome, FaUsers, FaChartBar, FaCog } from "react-icons/fa";
import styles from "./userdashboard.module.css"; // Import the CSS module

const UserDashboard = () => {
  const navigate = useNavigate();

  return (
    <div className={styles.container}>
      {/* Vertical Sidebar */}
      <div className={styles.sidebar}>
        <img src="/assets/ODCSE Logo.png" alt="Logo" className={styles.logo} />
        <ul className={styles.navList}>
          <li onClick={() => navigate("/")}> <FaHome className={styles.navIcon} /> Dashboard </li>
          <li onClick={() => navigate("/customers")}> <FaUsers className={styles.navIcon} /> Customers </li>
          <li onClick={() => navigate("/reports")}> <FaChartBar className={styles.navIcon} /> Reports </li>
          <li onClick={() => navigate("/settings")}> <FaCog className={styles.navIcon} /> Settings </li>
        </ul>
      </div>
      {/* Main Content */}
      <div className={styles.mainContent}>
        <div className={styles.header}>
          <div className={styles.iconContainer}>
            <FaRegBell className={styles.bellIcon} onClick={() => navigate("/notifications")} />
            <FaUserCircle className={styles.userIcon} onClick={() => navigate("/profile")} />
          </div>
        </div>
        <h1 className={styles.title}>Welcome to User Dashboard</h1>
      </div>
    </div>
  );
};

export default UserDashboard;
